"""CRUD routes — generated by doql."""
from fastapi import APIRouter, Depends, HTTPException
from sqlalchemy.orm import Session
from database import get_db
import models
import schemas

router = APIRouter(prefix='/api/v1')

# ── Notebook ──

@router.get("/notebooks", response_model=list[schemas.NotebookResponse])
def list_notebooks(skip: int = 0, limit: int = 100, db: Session = Depends(get_db)):
    return db.query(models.Notebook).offset(skip).limit(limit).all()

@router.get("/notebooks/{item_id}", response_model=schemas.NotebookResponse)
def get_notebook(item_id: str, db: Session = Depends(get_db)):
    obj = db.query(models.Notebook).filter(models.Notebook.id == item_id).first()
    if not obj:
        raise HTTPException(404, "Notebook not found")
    return obj

@router.post("/notebooks", response_model=schemas.NotebookResponse, status_code=201)
def create_notebook(data: schemas.NotebookCreate, db: Session = Depends(get_db)):
    import uuid as _uuid
    payload = data.model_dump()
    payload.setdefault('id', str(_uuid.uuid4()))
    obj = models.Notebook(**payload)
    db.add(obj)
    db.commit()
    db.refresh(obj)
    return obj

@router.patch("/notebooks/{item_id}", response_model=schemas.NotebookResponse)
def update_notebook(item_id: str, data: schemas.NotebookUpdate, db: Session = Depends(get_db)):
    obj = db.query(models.Notebook).filter(models.Notebook.id == item_id).first()
    if not obj:
        raise HTTPException(404, "Notebook not found")
    for key, val in data.model_dump(exclude_unset=True).items():
        setattr(obj, key, val)
    db.commit()
    db.refresh(obj)
    return obj

@router.delete("/notebooks/{item_id}", status_code=204)
def delete_notebook(item_id: str, db: Session = Depends(get_db)):
    obj = db.query(models.Notebook).filter(models.Notebook.id == item_id).first()
    if not obj:
        raise HTTPException(404, "Notebook not found")
    db.delete(obj)
    db.commit()

